type DepthDrawMode int64 //gd:BaseMaterial3D.DepthDrawMode

const (
	// Default depth draw mode. Depth is drawn only for opaque objects during the opaque prepass (if any) and during the opaque pass.
	DepthDrawOpaqueOnly DepthDrawMode = 0
	// Objects will write to depth during the opaque and the transparent passes. Transparent objects that are close to the camera may obscure other transparent objects behind them.
	//
	// Note: This does not influence whether transparent objects are included in the depth prepass or not. For that, see [Transparency].
	DepthDrawAlways DepthDrawMode = 1
	// Objects will not write their depth to the depth buffer, even during the depth prepass (if enabled).
	DepthDrawDisabled DepthDrawMode = 2
)

type DepthTest int64 //gd:BaseMaterial3D.DepthTest

const (
	// Depth test will discard the pixel if it is behind other pixels.
	DepthTestDefault DepthTest = 0
	// Depth test will discard the pixel if it is in front of other pixels. Useful for stencil effects.
	DepthTestInverted DepthTest = 1
)

type CullMode int64 //gd:BaseMaterial3D.CullMode

const (
	// Default cull mode. The back of the object is culled when not visible. Back face triangles will be culled when facing the camera. This results in only the front side of triangles being drawn. For closed-surface meshes, this means that only the exterior of the mesh will be visible.
	CullBack CullMode = 0
	// Front face triangles will be culled when facing the camera. This results in only the back side of triangles being drawn. For closed-surface meshes, this means that the interior of the mesh will be drawn instead of the exterior.
	CullFront CullMode = 1
	// No face culling is performed; both the front face and back face will be visible.
	CullDisabled CullMode = 2
)

type Flags int64 //gd:BaseMaterial3D.Flags

const (
	// Disables the depth test, so this object is drawn on top of all others drawn before it. This puts the object in the transparent draw pass where it is sorted based on distance to camera. Objects drawn after it in the draw order may cover it. This also disables writing to depth.
	FlagDisableDepthTest Flags = 0
	// Set ALBEDO to the per-vertex color specified in the mesh.
	FlagAlbedoFromVertexColor Flags = 1
	// Vertex colors are considered to be stored in nonlinear sRGB encoding and are converted to linear encoding during rendering. See also [VertexColorIsSrgb].
	//
	// Note: Only effective when using the Forward+ and Mobile rendering methods.
	//
	// [VertexColorIsSrgb]: https://pkg.go.dev/graphics.gd/classdb/#Instance.VertexColorIsSrgb
	FlagSrgbVertexColor Flags = 2
	// Uses point size to alter the size of primitive points. Also changes the albedo texture lookup to use POINT_COORD instead of UV.
	FlagUsePointSize Flags = 3
	// Object is scaled by depth so that it always appears the same size on screen.
	FlagFixedSize Flags = 4
	// Shader will keep the scale set for the mesh. Otherwise the scale is lost when billboarding. Only applies when [BillboardMode] is [BillboardEnabled].
	//
	// [BillboardMode]: https://pkg.go.dev/graphics.gd/classdb/#Instance.BillboardMode
	FlagBillboardKeepScale Flags = 5
	// Use triplanar texture lookup for all texture lookups that would normally use UV.
	FlagUv1UseTriplanar Flags = 6
	// Use triplanar texture lookup for all texture lookups that would normally use UV2.
	FlagUv2UseTriplanar Flags = 7
	// Use triplanar texture lookup for all texture lookups that would normally use UV.
	FlagUv1UseWorldTriplanar Flags = 8
	// Use triplanar texture lookup for all texture lookups that would normally use UV2.
	FlagUv2UseWorldTriplanar Flags = 9
	// Use UV2 coordinates to look up from the [AoTexture].
	//
	// [AoTexture]: https://pkg.go.dev/graphics.gd/classdb/#Instance.AoTexture
	FlagAoOnUv2 Flags = 10
	// Use UV2 coordinates to look up from the [EmissionTexture].
	//
	// [EmissionTexture]: https://pkg.go.dev/graphics.gd/classdb/#Instance.EmissionTexture
	FlagEmissionOnUv2 Flags = 11
	// Forces the shader to convert albedo from nonlinear sRGB encoding to linear encoding. See also [AlbedoTextureForceSrgb].
	//
	// [AlbedoTextureForceSrgb]: https://pkg.go.dev/graphics.gd/classdb/#Instance.AlbedoTextureForceSrgb
	FlagAlbedoTextureForceSrgb Flags = 12
	// Disables receiving shadows from other objects.
	FlagDontReceiveShadows Flags = 13
	// Disables receiving ambient light.
	FlagDisableAmbientLight Flags = 14
	// Enables the shadow to opacity feature.
	FlagUseShadowToOpacity Flags = 15
	// Enables the texture to repeat when UV coordinates are outside the 0-1 range. If using one of the linear filtering modes, this can result in artifacts at the edges of a texture when the sampler filters across the edges of the texture.
	FlagUseTextureRepeat Flags = 16
	// Invert values read from a depth texture to convert them to height values (heightmap).
	FlagInvertHeightmap Flags = 17
	// Enables the skin mode for subsurface scattering which is used to improve the look of subsurface scattering when used for human skin.
	FlagSubsurfaceModeSkin Flags = 18
	// Enables parts of the shader required for [GPUParticles3D] trails to function. This also requires using a mesh with appropriate skinning, such as [RibbonTrailMesh] or [TubeTrailMesh]. Enabling this feature outside of materials used in [GPUParticles3D] meshes will break material rendering.
	//
	// [GPUParticles3D]: https://pkg.go.dev/graphics.gd/classdb/GPUParticles3D
	// [RibbonTrailMesh]: https://pkg.go.dev/graphics.gd/classdb/RibbonTrailMesh
	// [TubeTrailMesh]: https://pkg.go.dev/graphics.gd/classdb/TubeTrailMesh
	FlagParticleTrailsMode Flags = 19
	// Enables multichannel signed distance field rendering shader.
	FlagAlbedoTextureMsdf Flags = 20
	// Disables receiving depth-based or volumetric fog.
	FlagDisableFog Flags = 21
	// Disables specular occlusion.
	FlagDisableSpecularOcclusion Flags = 22
	// Enables using [ZClipScale].
	//
	// [ZClipScale]: https://pkg.go.dev/graphics.gd/classdb/#Instance.ZClipScale
	FlagUseZClipScale Flags = 23
	// Enables using [FovOverride].
	//
	// [FovOverride]: https://pkg.go.dev/graphics.gd/classdb/#Instance.FovOverride
	FlagUseFovOverride Flags = 24
	// Represents the size of the [Flags] enum.
	FlagMax Flags = 25
)

type DiffuseMode int64 //gd:BaseMaterial3D.DiffuseMode

const (
	// Default diffuse scattering algorithm.
	DiffuseBurley DiffuseMode = 0
	// Diffuse scattering ignores roughness.
	DiffuseLambert DiffuseMode = 1
	// Extends Lambert to cover more than 90 degrees when roughness increases.
	DiffuseLambertWrap DiffuseMode = 2
	// Uses a hard cut for lighting, with smoothing affected by roughness.
	DiffuseToon DiffuseMode = 3
)

type SpecularMode int64 //gd:BaseMaterial3D.SpecularMode

const (
	// Default specular blob.
	//
	// Note: Forward+ uses multiscattering for more accurate reflections, although the impact of multiscattering is more noticeable on rough metallic surfaces than on smooth, non-metallic surfaces.
	//
	// Note: Mobile and Compatibility don't perform multiscattering for performance reasons. Instead, they perform single scattering, which means rough metallic surfaces may look slightly darker than intended.
	SpecularSchlickGgx SpecularMode = 0
	// Toon blob which changes size based on roughness.
	SpecularToon SpecularMode = 1
	// No specular blob. This is slightly faster to render than other specular modes.
	SpecularDisabled SpecularMode = 2
)

type BillboardMode int64 //gd:BaseMaterial3D.BillboardMode

const (
	// Billboard mode is disabled.
	BillboardDisabled BillboardMode = 0
	// The object's Z axis will always face the camera.
	BillboardEnabled BillboardMode = 1
	// The object's X axis will always face the camera.
	BillboardFixedY BillboardMode = 2
	// Used for particle systems when assigned to [GPUParticles3D] and [CPUParticles3D] nodes (flipbook animation). Enables particles_anim_* properties.
	//
	// The [ParticleProcessMaterial.AnimSpeedMin] or [CPUParticles3D.AnimSpeedMin] should also be set to a value bigger than zero for the animation to play.
	//
	// [CPUParticles3D]: https://pkg.go.dev/graphics.gd/classdb/CPUParticles3D
	// [CPUParticles3D.AnimSpeedMin]: https://pkg.go.dev/graphics.gd/classdb/CPUParticles3D#Instance.AnimSpeedMin
	// [GPUParticles3D]: https://pkg.go.dev/graphics.gd/classdb/GPUParticles3D
	// [ParticleProcessMaterial.AnimSpeedMin]: https://pkg.go.dev/graphics.gd/classdb/ParticleProcessMaterial#Instance.AnimSpeedMin
	BillboardParticles BillboardMode = 3
)

type TextureChannel int64 //gd:BaseMaterial3D.TextureChannel

const (
	// Used to read from the red channel of a texture.
	TextureChannelRed TextureChannel = 0
	// Used to read from the green channel of a texture.
	TextureChannelGreen TextureChannel = 1
	// Used to read from the blue channel of a texture.
	TextureChannelBlue TextureChannel = 2
	// Used to read from the alpha channel of a texture.
	TextureChannelAlpha TextureChannel = 3
	// Used to read from the linear (non-perceptual) average of the red, green and blue channels of a texture.
	TextureChannelGrayscale TextureChannel = 4
)

type EmissionOperator int64 //gd:BaseMaterial3D.EmissionOperator

const (
	// Adds the emission color to the color from the emission texture.
	EmissionOpAdd EmissionOperator = 0
	// Multiplies the emission color by the color from the emission texture.
	EmissionOpMultiply EmissionOperator = 1
)

type DistanceFadeMode int64 //gd:BaseMaterial3D.DistanceFadeMode

const (
	// Do not use distance fade.
	DistanceFadeDisabled DistanceFadeMode = 0
	// Smoothly fades the object out based on each pixel's distance from the camera using the alpha channel.
	DistanceFadePixelAlpha DistanceFadeMode = 1
	// Smoothly fades the object out based on each pixel's distance from the camera using a dithering approach. Dithering discards pixels based on a set pattern to smoothly fade without enabling transparency. On certain hardware, this can be faster than [DistanceFadePixelAlpha].
	DistanceFadePixelDither DistanceFadeMode = 2
	// Smoothly fades the object out based on the object's distance from the camera using a dithering approach. Dithering discards pixels based on a set pattern to smoothly fade without enabling transparency. On certain hardware, this can be faster than [DistanceFadePixelAlpha] and [DistanceFadePixelDither].
	DistanceFadeObjectDither DistanceFadeMode = 3
)

type StencilMode int64 //gd:BaseMaterial3D.StencilMode

const (
	// Disables stencil operations.
	StencilModeDisabled StencilMode = 0
	// Stencil preset which applies an outline to the object.
	//
	// Note: Requires a [Material.NextPass] material which will be automatically applied. Any manual changes made to [Material.NextPass] will be lost when the stencil properties are modified or the scene is reloaded. To safely apply a [Material.NextPass] material on a material that uses stencil presets, use [GeometryInstance3D.MaterialOverlay] instead.
	//
	// [GeometryInstance3D.MaterialOverlay]: https://pkg.go.dev/graphics.gd/classdb/GeometryInstance3D#Instance.MaterialOverlay
	// [Material.NextPass]: https://pkg.go.dev/graphics.gd/classdb/Material#Instance.NextPass
	StencilModeOutline StencilMode = 1
	// Stencil preset which shows a silhouette of the object behind walls.
	//
	// Note: Requires a [Material.NextPass] material which will be automatically applied. Any manual changes made to [Material.NextPass] will be lost when the stencil properties are modified or the scene is reloaded. To safely apply a [Material.NextPass] material on a material that uses stencil presets, use [GeometryInstance3D.MaterialOverlay] instead.
	//
	// [GeometryInstance3D.MaterialOverlay]: https://pkg.go.dev/graphics.gd/classdb/GeometryInstance3D#Instance.MaterialOverlay
	// [Material.NextPass]: https://pkg.go.dev/graphics.gd/classdb/Material#Instance.NextPass
	StencilModeXray StencilMode = 2
	// Enables stencil operations without a preset.
	StencilModeCustom StencilMode = 3
)

type StencilFlags int64 //gd:BaseMaterial3D.StencilFlags

const (
	// The material will only be rendered where it passes a stencil comparison with existing stencil buffer values.
	StencilFlagRead StencilFlags = 1
	// The material will write the reference value to the stencil buffer where it passes the depth test.
	StencilFlagWrite StencilFlags = 2
	// The material will write the reference value to the stencil buffer where it fails the depth test.
	StencilFlagWriteDepthFail StencilFlags = 4
)

type StencilCompare int64 //gd:BaseMaterial3D.StencilCompare

const (
	// Always passes the stencil test.
	StencilCompareAlways StencilCompare = 0
	// Passes the stencil test when the reference value is less than the existing stencil value.
	StencilCompareLess StencilCompare = 1
	// Passes the stencil test when the reference value is equal to the existing stencil value.
	StencilCompareEqual StencilCompare = 2
	// Passes the stencil test when the reference value is less than or equal to the existing stencil value.
	StencilCompareLessOrEqual StencilCompare = 3
	// Passes the stencil test when the reference value is greater than the existing stencil value.
	StencilCompareGreater StencilCompare = 4
	// Passes the stencil test when the reference value is not equal to the existing stencil value.
	StencilCompareNotEqual StencilCompare = 5
	// Passes the stencil test when the reference value is greater than or equal to the existing stencil value.
	StencilCompareGreaterOrEqual StencilCompare = 6
)
